588 // Return the number of iterations we want to peel off.
589 void llvm::computePeelCount(Loop *L, unsigned LoopSize,
590                             TargetTransformInfo::PeelingPreferences &PP,
591                             unsigned TripCount, DominatorTree &DT,
592                             ScalarEvolution &SE, AssumptionCache *AC,
593                             unsigned Threshold) {
594   assert(LoopSize > 0 && "Zero loop size is not allowed!");
595   // Save the PP.PeelCount value set by the target in
596   // TTI.getPeelingPreferences or by the flag -unroll-peel-count.
597   unsigned TargetPeelCount = PP.PeelCount;
598   PP.PeelCount = 0;
599   PP.PeelLast = false;
600   if (!canPeel(L))
601     return;
602 
603   // Only try to peel innermost loops by default.
604   // The constraint can be relaxed by the target in TTI.getPeelingPreferences
605   // or by the flag -unroll-allow-loop-nests-peeling.
606   if (!PP.AllowLoopNestsPeeling && !L->isInnermost())
607     return;
608 
609   // If the user provided a peel count, use that.
610   bool UserPeelCount = UnrollForcePeelCount.getNumOccurrences() > 0;
611   if (UserPeelCount) {
612     LLVM_DEBUG(dbgs() << "Force-peeling first " << UnrollForcePeelCount
613                       << " iterations.\n");
614     PP.PeelCount = UnrollForcePeelCount;
615     PP.PeelProfiledIterations = true;
616     return;
617   }
618 
619   // Skip peeling if it's disabled.
620   if (!PP.AllowPeeling)
621     return;
622 
623   // Check that we can peel at least one iteration.
624   if (2 * LoopSize > Threshold)
625     return;
626 
627   unsigned AlreadyPeeled = 0;
628   if (auto Peeled = getOptionalIntLoopAttribute(L, PeeledCountMetaData))
629     AlreadyPeeled = *Peeled;
630   // Stop if we already peeled off the maximum number of iterations.
631   if (AlreadyPeeled >= UnrollPeelMaxCount)
632     return;
633 
634   // Pay respect to limitations implied by loop size and the max peel count.
635   unsigned MaxPeelCount = UnrollPeelMaxCount;
636   MaxPeelCount = std::min(MaxPeelCount, Threshold / LoopSize - 1);
637 
638   // Start the max computation with the PP.PeelCount value set by the target
639   // in TTI.getPeelingPreferences or by the flag -unroll-peel-count.
640   unsigned DesiredPeelCount = TargetPeelCount;
641 
642   // Here we try to get rid of Phis which become invariants after 1, 2, ..., N
643   // iterations of the loop. For this we compute the number for iterations after
644   // which every Phi is guaranteed to become an invariant, and try to peel the
645   // maximum number of iterations among these values, thus turning all those
646   // Phis into invariants.
647   if (MaxPeelCount > DesiredPeelCount) {
648     // Check how many iterations are useful for resolving Phis
649     auto NumPeels = PhiAnalyzer(*L, MaxPeelCount).calculateIterationsToPeel();
650     if (NumPeels)
651       DesiredPeelCount = std::max(DesiredPeelCount, *NumPeels);
652   }
653 
654   const auto &[CountToEliminateCmps, CountToEliminateCmpsLast] =
655       countToEliminateCompares(*L, MaxPeelCount, SE);
656   DesiredPeelCount = std::max(DesiredPeelCount, CountToEliminateCmps);
657 
658   if (DesiredPeelCount == 0)
659     DesiredPeelCount = peelToTurnInvariantLoadsDerefencebale(*L, DT, AC);
660 
661   if (DesiredPeelCount > 0) {
662     DesiredPeelCount = std::min(DesiredPeelCount, MaxPeelCount);
663     // Consider max peel count limitation.
664     assert(DesiredPeelCount > 0 && "Wrong loop size estimation?");
665     if (DesiredPeelCount + AlreadyPeeled <= UnrollPeelMaxCount) {
666       LLVM_DEBUG(dbgs() << "Peel " << DesiredPeelCount
667                         << " iteration(s) to turn"
668                         << " some Phis into invariants.\n");
669       PP.PeelCount = DesiredPeelCount;
670       PP.PeelProfiledIterations = false;
671       PP.PeelLast = false;
672       return;
673     }
674   }
675 
676   if (CountToEliminateCmpsLast > 0) {
677     unsigned DesiredPeelCountLast =
678         std::min(CountToEliminateCmpsLast, MaxPeelCount);
679     // Consider max peel count limitation.
680     assert(DesiredPeelCountLast > 0 && "Wrong loop size estimation?");
681     if (DesiredPeelCountLast + AlreadyPeeled <= UnrollPeelMaxCount) {
682       LLVM_DEBUG(dbgs() << "Peel " << DesiredPeelCount
683                         << " iteration(s) to turn"
684                         << " some Phis into invariants.\n");
685       PP.PeelCount = DesiredPeelCountLast;
686       PP.PeelProfiledIterations = false;
687       PP.PeelLast = true;
688       return;
