 919     }
 920   } else {
 921     // For the first iteration, we use the value from the preheader directly.
 922     // For any other iteration, we replace the phi with the value generated by
 923     // the immediately preceding clone of the loop body (which represents
 924     // the previous iteration).
 925     for (BasicBlock::iterator I = Header->begin(); isa<PHINode>(I); ++I) {
