 932         if (LatchInst && L->contains(LatchInst))
 933           VMap[&*I] = LVMap[LatchInst];
 934         else
 935           VMap[&*I] = LatchVal;
 936       }
 937       NewPHI->eraseFromParent();
 938     }
 939   }
 940 
 941   // Fix up the outgoing values - we need to add a value for the iteration
 942   // we've just created. Note that this must happen *after* the incoming
 943   // values are adjusted, since the value going out of the latch may also be
 944   // a value coming into the header.
 945   for (auto Edge : ExitEdges)
 946     for (PHINode &PHI : Edge.second->phis()) {
 947       Value *LatchVal = PHI.getIncomingValueForBlock(Edge.first);
 948       Instruction *LatchInst = dyn_cast<Instruction>(LatchVal);
 949       if (LatchInst && L->contains(LatchInst))
 950         LatchVal = VMap[LatchVal];
 951       PHI.addIncoming(LatchVal, cast<BasicBlock>(VMap[Edge.first]));
 952       SE.forgetLcssaPhiWithNewPredecessor(L, &PHI);
 953     }
 954 
 955   // LastValueMap is updated with the values for the current loop
 956   // which are used the next time this function is called.
 957   for (auto KV : VMap)
 958     LVMap[KV.first] = KV.second;
 959 }
