1519   SmallPtrSet<Loop *, 4> OldLoops;
1520   if (ParentL)
1521     OldLoops.insert_range(*ParentL);
1522   else
1523     OldLoops.insert_range(AR.LI);
1524 
1525   std::string LoopName = std::string(L.getName());
1526 
1527   bool Changed =
1528       tryToUnrollLoop(&L, AR.DT, &AR.LI, AR.SE, AR.TTI, AR.AC, ORE,
1529                       /*BFI*/ nullptr, /*PSI*/ nullptr,
1530                       /*PreserveLCSSA*/ true, OptLevel, /*OnlyFullUnroll*/ true,
1531                       OnlyWhenForced, ForgetSCEV, /*Count*/ std::nullopt,
1532                       /*Threshold*/ std::nullopt, /*AllowPartial*/ false,
1533                       /*Runtime*/ false, /*UpperBound*/ false,
1534                       /*AllowPeeling*/ true,
1535                       /*AllowProfileBasedPeeling*/ false,
1536                       /*FullUnrollMaxCount*/ std::nullopt) !=
1537       LoopUnrollResult::Unmodified;
